import{_ as a,o as r,c as d,a2 as o}from"./chunks/framework.DZO5kRrk.js";const b=JSON.parse('{"title":"证件照工坊 — 产品需求文档(PRD)","description":"","frontmatter":{},"headers":[],"relativePath":"mvp.md","filePath":"mvp.md"}'),e={name:"mvp.md"};function l(i,t,h,n,u,s){return r(),d("div",null,[...t[0]||(t[0]=[o('<h1 id="证件照工坊-—-产品需求文档-prd" tabindex="-1">证件照工坊 — 产品需求文档(PRD) <a class="header-anchor" href="#证件照工坊-—-产品需求文档-prd" aria-label="Permalink to &quot;证件照工坊 — 产品需求文档(PRD)&quot;">​</a></h1><p><strong>版本</strong>: v0.1 draft <strong>平台</strong>: HarmonyOS NEXT(纯血鸿蒙) <strong>日期</strong>: 2026-07</p><hr><h2 id="_1-背景与机会" tabindex="-1">1. 背景与机会 <a class="header-anchor" href="#_1-背景与机会" aria-label="Permalink to &quot;1. 背景与机会&quot;">​</a></h2><h3 id="_1-1-市场缺口" tabindex="-1">1.1 市场缺口 <a class="header-anchor" href="#_1-1-市场缺口" aria-label="Permalink to &quot;1.1 市场缺口&quot;">​</a></h3><ul><li>鸿蒙原生应用生态目前处于&quot;设备多、应用少&quot;的阶段(4200万+ 装机量,原生应用约1.5万款),证件照这个具体细分场景<strong>没有成熟的深度产品</strong>。</li><li>已上架的&quot;白描 PDF&quot;覆盖了扫描/OCR/PDF转换的大盘子,证件照只是其中一个附属小功能,不是主打场景,没有覆盖到证件照场景真正的核心痛点(精确像素/文件体积合规、多场景尺寸库)。</li><li>证件照是<strong>高频刚需、低替代性</strong>的场景:入学、考试报名、签证、驾照、职业资格证、社保、招聘网站……几乎每个成年人每年都会用到 1-3 次,且经常在&quot;临时需要、马上要交&quot;的场景下发生,付费意愿强。</li></ul><h3 id="_1-2-为什么适合做成鸿蒙原生-app-而不是小程序-网页" tabindex="-1">1.2 为什么适合做成鸿蒙原生 App(而不是小程序/网页) <a class="header-anchor" href="#_1-2-为什么适合做成鸿蒙原生-app-而不是小程序-网页" aria-label="Permalink to &quot;1.2 为什么适合做成鸿蒙原生 App(而不是小程序/网页)&quot;">​</a></h3><ul><li>抠图、换底色、压缩这些操作全部可以<strong>离线完成</strong>,不需要服务器,零运维成本。</li><li>华为系统自带 <strong>Core Vision Kit</strong>(人像分割/人脸检测)可以直接调用,不需要自己训练部署 AI 模型,大幅降低开发成本。</li><li>&quot;证件照涉及身份证件照片,处理过程不上传云端&quot;是天然的信任卖点,尤其对中老年用户、体制内考试用户群体有很强说服力。</li></ul><h3 id="_1-3-应对鸿蒙审核-3-5-条款-功能独特性" tabindex="-1">1.3 应对鸿蒙审核 3.5 条款(功能独特性) <a class="header-anchor" href="#_1-3-应对鸿蒙审核-3-5-条款-功能独特性" aria-label="Permalink to &quot;1.3 应对鸿蒙审核 3.5 条款(功能独特性)&quot;">​</a></h3><p>鸿蒙审核对&quot;功能单一、缺乏实质服务&quot;的应用有明确驳回倾向,因此本产品<strong>不做成单一功能的&quot;换底色工具&quot;</strong>,而是围绕&quot;证件照制作全流程&quot;设计一组强关联功能形成完整服务闭环(详见第 4 节)。</p><hr><h2 id="_2-目标用户与场景" tabindex="-1">2. 目标用户与场景 <a class="header-anchor" href="#_2-目标用户与场景" aria-label="Permalink to &quot;2. 目标用户与场景&quot;">​</a></h2><table tabindex="0"><thead><tr><th>用户群体</th><th>典型场景</th><th>核心诉求</th></tr></thead><tbody><tr><td>应届生/求职者</td><td>网申简历照、offer入职材料</td><td>快速出图、多底色备用</td></tr><tr><td>考公考编/考研考生</td><td>报名系统上传证件照</td><td>精确匹配&quot;XX考试专用尺寸+文件大小(KB)&quot;</td></tr><tr><td>签证/出国人群</td><td>各国签证照片规格</td><td>国际尺寸标准库、白底强制要求</td></tr><tr><td>中老年/办事群体</td><td>社保卡、驾照换证</td><td>操作简单、不需要注册、不联网更放心</td></tr><tr><td>职场人士</td><td>工作证、内部系统头像</td><td>批量导出多规格</td></tr></tbody></table><hr><h2 id="_3-竞品简析" tabindex="-1">3. 竞品简析 <a class="header-anchor" href="#_3-竞品简析" aria-label="Permalink to &quot;3. 竞品简析&quot;">​</a></h2><table tabindex="0"><thead><tr><th>产品</th><th>定位</th><th>与本产品的差异</th></tr></thead><tbody><tr><td>白描 PDF(鸿蒙版)</td><td>文档扫描/OCR/PDF工具,证件照是附属功能</td><td>证件照场景做得浅,尺寸库不全,非核心卖点</td></tr><tr><td>天天P图/美图证件照(安卓/iOS)</td><td>泛修图 App 的证件照子功能</td><td>未上架鸿蒙,且偏&quot;美颜&quot;而非&quot;合规工具&quot;</td></tr><tr><td>各类考试官方系统自带裁图工具</td><td>仅限特定考试使用</td><td>不通用,体验差,常见&quot;上传失败&quot;投诉</td></tr></tbody></table><p><strong>差异化定位一句话</strong>:不是修图 App,是&quot;证件照合规工具&quot;——核心价值是<strong>尺寸和文件大小精确匹配官方要求</strong>,美颜是锦上添花不是主打。</p><hr><h2 id="_4-核心功能模块-mvp-范围" tabindex="-1">4. 核心功能模块(MVP 范围) <a class="header-anchor" href="#_4-核心功能模块-mvp-范围" aria-label="Permalink to &quot;4. 核心功能模块(MVP 范围)&quot;">​</a></h2><p>为满足审核对&quot;功能完整性&quot;的要求,MVP 包含以下 5 个强关联模块,形成&quot;选场景 → 拍/传照片 → 智能处理 → 合规校验 → 导出/打印&quot;的完整闭环:</p><h3 id="_4-1-场景化尺寸库-核心差异点" tabindex="-1">4.1 场景化尺寸库(核心差异点) <a class="header-anchor" href="#_4-1-场景化尺寸库-核心差异点" aria-label="Permalink to &quot;4.1 场景化尺寸库(核心差异点)&quot;">​</a></h3><ul><li>内置国家标准 + 常见考试/证件的尺寸数据库,按分类检索: <ul><li>身份证件类:一代/二代身份证、护照、港澳通行证、驾驶证</li><li>考试类:教师资格证、计算机等级考试、公务员考试、研究生考试、四六级</li><li>签证类:美签、日签、申根签等主要国家标准</li><li>求职类:简历照、工作证</li></ul></li><li>每条记录包含:像素尺寸、mm物理尺寸、文件大小要求(KB区间)、背景色要求、DPI</li><li>支持关键词搜索(如输入&quot;教师资格证&quot;直接匹配对应规格)</li></ul><h3 id="_4-2-智能抠图-换底色" tabindex="-1">4.2 智能抠图 + 换底色 <a class="header-anchor" href="#_4-2-智能抠图-换底色" aria-label="Permalink to &quot;4.2 智能抠图 + 换底色&quot;">​</a></h3><ul><li>调用系统 Core Vision Kit 人像分割能力,自动抠出人像</li><li>一键替换为标准底色:白/红/蓝(国标证件照三色)</li><li>人脸检测辅助自动居中、按照标准比例裁剪(眼睛位置、头顶留白比例符合规范)</li></ul><h3 id="_4-3-文件大小精确压缩-高痛点、差异化" tabindex="-1">4.3 文件大小精确压缩(高痛点、差异化) <a class="header-anchor" href="#_4-3-文件大小精确压缩-高痛点、差异化" aria-label="Permalink to &quot;4.3 文件大小精确压缩(高痛点、差异化)&quot;">​</a></h3><ul><li>很多报名系统要求&quot;文件大小需在 20KB-200KB 之间&quot;,用户常年被这个要求卡住反复尝试</li><li>本产品支持<strong>指定目标文件大小区间</strong>,自动通过质量/尺寸调整迭代压缩至符合要求,而不是让用户自己试错调整压缩率</li></ul><h3 id="_4-4-排版打印" tabindex="-1">4.4 排版打印 <a class="header-anchor" href="#_4-4-排版打印" aria-label="Permalink to &quot;4.4 排版打印&quot;">​</a></h3><ul><li>支持将证件照按照冲印规格排版(如六寸相纸排 8 张一寸/6 张二寸),生成可直接送冲印店打印的排版图</li><li>常见于线下办事仍需要纸质照片的场景(如部分政务窗口)</li></ul><h3 id="_4-5-批量导出" tabindex="-1">4.5 批量导出 <a class="header-anchor" href="#_4-5-批量导出" aria-label="Permalink to &quot;4.5 批量导出&quot;">​</a></h3><ul><li>一次拍摄/上传,勾选多个尺寸规格,一键批量生成全部规格的成片,分别导出</li></ul><hr><h2 id="_5-非功能需求" tabindex="-1">5. 非功能需求 <a class="header-anchor" href="#_5-非功能需求" aria-label="Permalink to &quot;5. 非功能需求&quot;">​</a></h2><ul><li><strong>全离线处理</strong>:所有图像处理在本地完成,不上传服务器,App 权限说明中明确标注</li><li><strong>不强制注册登录</strong>:降低使用门槛,首次打开即可用</li><li><strong>性能</strong>:单张处理(抠图+换底色+裁剪)应在 2 秒内完成</li><li><strong>隐私合规</strong>:需在应用市场审核提交时清晰说明本地处理机制,避免被判定为&quot;涉及敏感证件照片&quot;额外审查</li></ul><hr><h2 id="_6-技术方案概要" tabindex="-1">6. 技术方案概要 <a class="header-anchor" href="#_6-技术方案概要" aria-label="Permalink to &quot;6. 技术方案概要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>技术方案</th></tr></thead><tbody><tr><td>UI 框架</td><td>ArkTS + ArkUI(声明式)</td></tr><tr><td>人像分割/人脸检测</td><td>Core Vision Kit(系统内置,免自建模型)</td></tr><tr><td>图像编解码/变换/压缩</td><td>Image Kit</td></tr><tr><td>尺寸库数据</td><td>本地 JSON 静态数据 + Preferences 做用户收藏</td></tr><tr><td>文件读写/导出</td><td>fileIo + DocumentViewPicker</td></tr><tr><td>打印排版渲染</td><td>Canvas 自绘</td></tr></tbody></table><blockquote><p>备注:该技术组合完全不依赖 MindSpore Lite 自训练模型,人像分割和人脸关键点检测都走系统能力,大幅降低你在 AI 模型转换/调优上的踩坑成本(参考此前 ImageToolbox 分析中提到的 NPU 算子兼容性问题——这里直接绕开了)。</p></blockquote><hr><h2 id="_7-商业化模式" tabindex="-1">7. 商业化模式 <a class="header-anchor" href="#_7-商业化模式" aria-label="Permalink to &quot;7. 商业化模式&quot;">​</a></h2><ul><li><strong>基础版免费</strong>:常用尺寸(身份证、简历照、护照)+ 基础换底色 + 压缩,永久免费,保证冷启动获客</li><li><strong>订阅解锁</strong>(参考白描定价区间,月付 6-12 元 / 年付 30-50 元): <ul><li>完整尺寸库(考试类、签证类全量)</li><li>批量导出无限制(免费版限制每次导出张数)</li><li>排版打印模板全解锁</li><li>去除处理过程中的水印(如有)</li></ul></li><li><strong>不做广告变现</strong>:证件照场景用户对&quot;隐私+专业感&quot;敏感,插广告会破坏信任感,不符合定位</li></ul><hr><h2 id="_8-里程碑规划" tabindex="-1">8. 里程碑规划 <a class="header-anchor" href="#_8-里程碑规划" aria-label="Permalink to &quot;8. 里程碑规划&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阶段</th><th>内容</th><th>预估周期</th></tr></thead><tbody><tr><td>Phase 1(MVP)</td><td>尺寸库(覆盖前20个最高频场景)+ 抠图换底色 + 尺寸裁剪 + 文件大小压缩</td><td>3-4 周</td></tr><tr><td>Phase 2</td><td>批量导出 + 排版打印</td><td>1-2 周</td></tr><tr><td>Phase 3</td><td>订阅体系接入 + 尺寸库扩充 + 用户反馈迭代</td><td>持续</td></tr><tr><td>Phase 4(可选)</td><td>折叠屏/平板适配,冲上华为&quot;星光大道&quot;推荐</td><td>视 Phase 1-3 数据决定</td></tr></tbody></table><hr><h2 id="_9-风险与应对" tabindex="-1">9. 风险与应对 <a class="header-anchor" href="#_9-风险与应对" aria-label="Permalink to &quot;9. 风险与应对&quot;">​</a></h2><table tabindex="0"><thead><tr><th>风险</th><th>应对方案</th></tr></thead><tbody><tr><td>审核 3.5 条款仍判定功能单薄</td><td>提交时突出&quot;尺寸数据库+合规校验&quot;的独特服务属性,而非单纯修图工具;可参考白描的应用描述话术</td></tr><tr><td>Core Vision Kit 人像分割精度不足(复杂背景)</td><td>MVP 阶段先支持&quot;纯色背景&quot;高精度场景,复杂背景标注为&quot;Beta&quot;逐步优化</td></tr><tr><td>尺寸库数据准确性(官方标准更新)</td><td>建立可远程更新的尺寸库(唯一联网需求点),避免因过时数据导致用户投诉</td></tr><tr><td>冷启动获客难</td><td>上线时主打&quot;考公考编报名季&quot;节点投放,配合华为应用市场编辑推荐位申请</td></tr></tbody></table><hr><h2 id="_10-成功指标-北极星指标" tabindex="-1">10. 成功指标(北极星指标) <a class="header-anchor" href="#_10-成功指标-北极星指标" aria-label="Permalink to &quot;10. 成功指标(北极星指标)&quot;">​</a></h2><ul><li>MVP 上线 90 天内:安装量 5,000+,应用市场评分 ≥ 4.5</li><li>付费转化率:参考同类工具类应用鸿蒙市场基准(5%+)</li><li>次月留存:因场景本身低频(非日活类工具),留存指标改为&quot;半年内二次使用率&quot; ≥ 30%</li></ul><hr><p><em>本 PRD 为 v0.1 草案,细节尺寸库数据、UI 稿、具体订阅定价需在开发前进一步调研确认。</em></p>',51)])])}const _=a(e,[["render",l]]);export{b as __pageData,_ as default};
